package com.tidex.mobile.meshimport android.Manifestimport android.annotation.SuppressLintimport android.bluetooth.BluetoothAdapterimport android.bluetooth.BluetoothManagerimport android.bluetooth.le.AdvertiseCallbackimport android.bluetooth.le.AdvertiseDataimport android.bluetooth.le.AdvertiseSettingsimport android.bluetooth.le.BluetoothLeAdvertiserimport android.bluetooth.le.BluetoothLeScannerimport android.bluetooth.le.ScanCallbackimport android.bluetooth.le.ScanFilterimport android.bluetooth.le.ScanResultimport android.bluetooth.le.ScanSettingsimport android.content.Contextimport android.content.pm.PackageManagerimport android.os.ParcelUuidimport android.util.Logimport androidx.core.content.ContextCompatimport java.nio.charset.StandardCharsetsimport java.util.UUIDclass BleMeshManager(private val context: Context) {    private val bluetoothManager = context.getSystemService(Context.BLUETOOTH_SERVICE) as BluetoothManager    private val adapter: BluetoothAdapter? = bluetoothManager.adapter    private val scanner: BluetoothLeScanner? get() = adapter?.bluetoothLeScanner    private val advertiser: BluetoothLeAdvertiser? get() = adapter?.bluetoothLeAdvertiser    private var scanCallback: ScanCallback? = null    private var advertiseCallback: AdvertiseCallback? = null    var onMessageReceived: ((SOSMessage) -> Unit)? = null    var onError: ((String) -> Unit)? = null    fun isBluetoothEnabled(): Boolean = adapter?.isEnabled == true    fun hasBlePermissions(): Boolean {        val scan = ContextCompat.checkSelfPermission(context, Manifest.permission.BLUETOOTH_SCAN) == PackageManager.PERMISSION_GRANTED        val advertise = ContextCompat.checkSelfPermission(context, Manifest.permission.BLUETOOTH_ADVERTISE) == PackageManager.PERMISSION_GRANTED        val connect = ContextCompat.checkSelfPermission(context, Manifest.permission.BLUETOOTH_CONNECT) == PackageManager.PERMISSION_GRANTED        return scan && advertise && connect    }    @SuppressLint("MissingPermission")    fun startScanning() {        if (!hasBlePermissions()) {            onError?.invoke("Missing BLE permissions")            return        }        if (!isBluetoothEnabled()) {            onError?.invoke("Bluetooth is OFF")            return        }        if (scanCallback != null) return        val filter = ScanFilter.Builder()            .setServiceUuid(ParcelUuid(SERVICE_UUID))            .build()        val settings = ScanSettings.Builder()            .setScanMode(ScanSettings.SCAN_MODE_LOW_LATENCY)            .build()        scanCallback = object : ScanCallback() {            override fun onScanResult(callbackType: Int, result: ScanResult) {                parseScanResult(result)            }            override fun onBatchScanResults(results: MutableList<ScanResult>) {                results.forEach { parseScanResult(it) }            }            override fun onScanFailed(errorCode: Int) {                onError?.invoke("BLE scan failed: $errorCode")            }        }        scanner?.startScan(listOf(filter), settings, scanCallback)        Log.i(TAG, "BLE scan started")    }    @SuppressLint("MissingPermission")    fun stopScanning() {        scanCallback?.let { scanner?.stopScan(it) }        scanCallback = null        Log.i(TAG, "BLE scan stopped")    }    @SuppressLint("MissingPermission")    fun advertiseMessage(message: SOSMessage) {        if (!hasBlePermissions()) {            onError?.invoke("Missing BLE permissions")            return        }        if (!isBluetoothEnabled()) {            onError?.invoke("Bluetooth is OFF")            return        }        val payload = message.toJsonString().toByteArray(StandardCharsets.UTF_8)        if (payload.size > MAX_ADV_BYTES) {            onError?.invoke("Payload too large for BLE advertisement (${payload.size} bytes)")            return        }        stopAdvertising()        val settings = AdvertiseSettings.Builder()            .setAdvertiseMode(AdvertiseSettings.ADVERTISE_MODE_LOW_LATENCY)            .setConnectable(false)            .setTimeout(0)            .setTxPowerLevel(AdvertiseSettings.ADVERTISE_TX_POWER_HIGH)            .build()        val data = AdvertiseData.Builder()            .addServiceUuid(ParcelUuid(SERVICE_UUID))            .addServiceData(ParcelUuid(SERVICE_UUID), payload)            .setIncludeDeviceName(false)            .setIncludeTxPowerLevel(false)            .build()        advertiseCallback = object : AdvertiseCallback() {            override fun onStartSuccess(settingsInEffect: AdvertiseSettings) {                Log.i(TAG, "SOS advertised: id=${message.id} ttl=${message.ttl}")            }            override fun onStartFailure(errorCode: Int) {                onError?.invoke("BLE advertise failed: $errorCode")            }        }        advertiser?.startAdvertising(settings, data, advertiseCallback)    }    @SuppressLint("MissingPermission")    fun stopAdvertising() {        advertiseCallback?.let { advertiser?.stopAdvertising(it) }        advertiseCallback = null    }    fun stopAll() {        stopScanning()        stopAdvertising()    }    private fun parseScanResult(result: ScanResult) {        val record = result.scanRecord ?: return        val bytes = record.getServiceData(ParcelUuid(SERVICE_UUID)) ?: return        try {            val rawJson = String(bytes, StandardCharsets.UTF_8)            val message = SOSMessage.fromJsonString(rawJson)            onMessageReceived?.invoke(message)        } catch (err: Exception) {            onError?.invoke("Decode error: ${err.message}")        }    }    companion object {        private const val TAG = "BleMeshManager"        // For legacy advertising payload safety.        private const val MAX_ADV_BYTES = 160        val SERVICE_UUID: UUID = UUID.fromString("4d4f5348-1000-4000-8000-000000000001")    }}